     1→"use client";
     2→
     3→import { useState, useRef, useEffect } from "react";
     4→import { Paperclip, Link as LinkIcon, Mic, X, Sparkles, ArrowDownLeft } from "lucide-react";
     5→import { useRouter } from "next/navigation";
     6→import Link from "next/link";
     7→import { cn } from "@/lib/utils";
     8→import { toast } from "sonner";
     9→import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
    10→import { useSpeechRecognition } from "@/hooks/use-speech-recognition";
    11→// import { UserNav } from "@/components/layout/user-nav"; 
    12→import { AuthModal } from "@/components/auth/auth-modal";
    13→import { AnalysisResults } from "@/components/capture/analysis-results";
    14→import { useLanguageStore } from "@/store/language-store";
    15→import { SiteHeader } from "@/components/layout/site-header";
    16→
    17→export default function CapturePage() {
    18→    const router = useRouter();
    19→    const { t, currentLang } = useLanguageStore();
    20→
    21→    // State
    22→    const [input, setInput] = useState("");
    23→    const [files, setFiles] = useState<File[]>([]);
    24→    const [links, setLinks] = useState<string[]>([]);
    25→    const [viewMode, setViewMode] = useState<"INPUT" | "ANALYZING">("INPUT");
    26→
    27→    // UI State
    28→    const [linkInput, setLinkInput] = useState("");
    29→    const [isLinkOpen, setIsLinkOpen] = useState(false);
    30→
    31→    // Refs
    32→    const textareaRef = useRef<HTMLTextAreaElement>(null);
    33→    const fileInputRef = useRef<HTMLInputElement>(null);
    34→
    35→    const { isRecording, toggleRecording } = useSpeechRecognition({
    36→        onFinal: (text) => {
    37→            setInput((prev) => {
    38→                const needsSpace = prev.length > 0 && !prev.endsWith(" ") && !prev.endsWith("\n");
    39→                return prev + (needsSpace ? " " : "") + text;
    40→            });
    41→        },
    42→        onError: (err) => toast.error("Erreur vocale", { description: err })
    43→    });
    44→
    45→    useEffect(() => {
    46→        document.documentElement.lang = currentLang.toLowerCase();
    47→    }, [currentLang]);
    48→
    49→    const handleSubmit = async () => {
    50→        if (!input.trim() && files.length === 0 && links.length === 0) return;
    51→        setViewMode("ANALYZING");
    52→        if (typeof window !== "undefined") {
    53→            const payload = {
    54→                text: input,
    55→                files: files.map(f => ({ name: f.name, type: f.type, size: f.size })),
    56→                links: links,
    57→                timestamp: new Date().toISOString()
    58→            };
    59→            localStorage.setItem("k3rn_current_idea", JSON.stringify(payload));
    60→        }
    61→    };
    62→
    63→    const handleReset = () => {
    64→        setViewMode("INPUT");
    65→        setInput("");
    66→        setFiles([]);
    67→        setLinks([]);
    68→    };
    69→
    70→    const handleKeyDown = (e: React.KeyboardEvent) => {
    71→        if ((e.metaKey || e.ctrlKey) && e.key === "Enter") {
    72→            handleSubmit();
    73→        }
    74→    };
    75→
    76→    const handleAttachFile = () => {
    77→        fileInputRef.current?.click();
    78→    };
    79→
    80→    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    81→        if (e.target.files && e.target.files.length > 0) {
    82→            const newFile = e.target.files[0];
    83→            setFiles(prev => [...prev, newFile]);
    84→            toast.success("Fichier joint", { description: newFile.name });
    85→            if (fileInputRef.current) fileInputRef.current.value = "";
    86→        }
    87→    };
    88→
    89→    const removeFile = (index: number) => {
    90→        setFiles(prev => prev.filter((_, i) => i !== index));
    91→    };
    92→
    93→    const addLink = () => {
    94→        if (!linkInput.trim()) return;
    95→        setLinks(prev => [...prev, linkInput]);
    96→        toast.success("Lien ajouté");
    97→        setLinkInput("");
    98→        setIsLinkOpen(false);
    99→    };
   100→
   101→    const removeLink = (index: number) => {
   102→        setLinks(prev => prev.filter((_, i) => i !== index));
   103→    };
   104→
   105→    // Focus on mount
   106→    useEffect(() => {
   107→        if (viewMode === "INPUT") {
   108→            textareaRef.current?.focus();
   109→        }
   110→    }, [viewMode]);
   111→
   112→    const hasContent = input.trim().length > 0 || files.length > 0 || links.length > 0;
   113→
   114→    return (
   115→        <div className="min-h-screen bg-background text-foreground flex flex-col font-sans selection:bg-[#F75105]/30">
   116→            <SiteHeader variant="app" />
   117→            <AuthModal />
   118→
   119→            {/* Main Content using Flex to Center */}
   120→            <main className="flex-1 w-full max-w-5xl mx-auto px-6 flex flex-col items-center justify-center gap-12 pb-24">
   121→
   122→                {/* Hero Text (Only in Input Mode) */}
   123→                {viewMode === "INPUT" && (
   124→                    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col gap-6 text-center max-w-2xl">
   125→                        <h1 className="text-6xl md:text-7xl font-light text-white tracking-tight leading-[1.0] font-sans">
   126→                            {t?.capture?.hero || "Capture Your Vision"}
   127→                        </h1>
   128→                        <p className="text-[#D2D3D4] font-light text-lg md:text-xl tracking-wide max-w-lg mx-auto leading-relaxed">
   129→                            {t?.capture?.helper || "From raw thought to structured project in seconds."}
   130→                        </p>
   131→                    </div>
   132→                )}
   133→
   134→                {/* INPUT CARD - MODERN ROUNDED (Radius 24px) */}
   135→                {viewMode === "INPUT" && (
   136→                    <div className="w-full max-w-3xl bg-[--bg-card] rounded-[24px] border border-[--border-default] p-8 shadow-2xl relative overflow-visible transition-all duration-300 hover:border-[--border-strong] animate-in zoom-in-95 backdrop-blur-sm group/card">
   137→
   138→                        {/* Textarea */}
   139→                        <textarea
   140→                            ref={textareaRef}
   141→                            value={input}
   142→                            onChange={(e) => setInput(e.target.value)}
   143→                            onKeyDown={handleKeyDown}
   144→                            className="w-full h-40 bg-transparent resize-none outline-none text-xl text-white placeholder:text-[#5D5C5B] font-light leading-relaxed scrollbar-hide"
   145→                            placeholder={t?.capture?.placeholder || "Describe your idea..."}
   146→                            autoFocus
   147→                        />
   148→
   149→                        {/* Attachments Preview */}
   150→                        {(files.length > 0 || links.length > 0) && (
   151→                            <div className="flex flex-wrap gap-2 mt-4 mb-4 pt-4 border-t border-[--border-subtle]">
   152→                                {files.map((file, index) => (
   153→                                    <div
   154→                                        key={index}
   155→                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
   156→                                    >
   157→                                        <Paperclip className="w-3 h-3 text-[#5D5C5B]" />
   158→                                        <span className="max-w-[150px] truncate">{file.name}</span>
   159→                                        <button
   160→                                            onClick={() => removeFile(index)}
   161→                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
   162→                                        >
   163→                                            <X className="w-3 h-3" />
   164→                                        </button>
   165→                                    </div>
   166→                                ))}
   167→                                {links.map((link, index) => (
   168→                                    <div
   169→                                        key={index}
   170→                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
   171→                                    >
   172→                                        <LinkIcon className="w-3 h-3 text-[#F75105]" />
   173→                                        <span className="max-w-[150px] truncate">{link}</span>
   174→                                        <button
   175→                                            onClick={() => removeLink(index)}
   176→                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
   177→                                        >
   178→                                            <X className="w-3 h-3" />
   179→                                        </button>
   180→                                    </div>
   181→                                ))}
   182→                            </div>
   183→                        )}
   184→
   185→                        {/* Hidden File Input */}
   186→                        <input
   187→                            type="file"
   188→                            ref={fileInputRef}
   189→                            className="hidden"
   190→                            onChange={handleFileChange}
   191→                        />
   192→
   193→                        {/* Actions Toolbar */}
   194→                        <div className="flex justify-between items-end mt-4">
   195→                            {/* Tools (Bottom Left) */}
   196→                            <div className="flex gap-2">
   197→                                {/* Attach File */}
   198→                                <button
   199→                                    onClick={handleAttachFile}
   200→                                    className="p-3 rounded-full hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white transition-all duration-300 active:scale-95 group/icon"
   201→                                    title={t?.capture?.attachFile || "Attach File"}
   202→                                >
   203→                                    <Paperclip className="w-5 h-5 transition-colors" />
   204→                                </button>
   205→
   206→                                {/* Add Link */}
   207→                                <Popover open={isLinkOpen} onOpenChange={setIsLinkOpen}>
   208→                                    <PopoverTrigger asChild>
   209→                                        <button
   210→                                            className={cn(
   211→                                                "p-3 rounded-full transition-all duration-300 active:scale-95 group/icon",
   212→                                                isLinkOpen ? "bg-[--bg-secondary] text-white" : "hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white"
   213→                                            )}
   214→                                            title={t?.capture?.addLink || "Add Link"}
   215→                                        >
   216→                                            <LinkIcon className="w-5 h-5 transition-colors" />
   217→                                        </button>
   218→                                    </PopoverTrigger>
   219→                                    <PopoverContent className="w-96 p-4 bg-[--bg-card] border border-[--border-default] rounded-[20px] shadow-2xl" align="start" sideOffset={12}>
   220→                                        <div className="flex gap-3">
   221→                                            <input
   222→                                                className="flex-1 px-4 py-3 text-sm bg-[--bg-secondary] border border-[--border-subtle] rounded-lg text-white placeholder:text-[#5D5C5B] focus:outline-none focus:border-[#F75105] transition-all font-light"
   223→                                                placeholder="https://example.com"
   224→                                                value={linkInput}
   225→                                                onChange={(e) => setLinkInput(e.target.value)}
   226→                                                onKeyDown={(e) => e.key === "Enter" && addLink()}
   227→                                                autoFocus
   228→                                            />
   229→                                            <button
   230→                                                onClick={addLink}
   231→                                                className="px-6 py-2 text-sm font-medium bg-[#F75105] text-white rounded-lg hover:bg-[#F78E21] hover:shadow-[0_0_20px_rgba(247,81,5,0.4)] transition-all"
   232→                                            >
   233→                                                Add
   234→                                            </button>
   235→                                        </div>
   236→                                    </PopoverContent>
   237→                                </Popover>
   238→
   239→                                {/* Voice Input (Static Orange Active State - Color Only) */}
   240→                                <button
   241→                                    onClick={toggleRecording}
   242→                                    className={cn(
   243→                                        "p-3 rounded-full transition-all duration-300 active:scale-95 group/mic",
   244→                                        isRecording
   245→                                            ? "text-[#F75105] hover:bg-[--bg-secondary]"
   246→                                            : "hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white"
   247→                                    )}
   248→                                    title={t?.capture?.voiceInput || "Voice Input"}
   249→                                >
   250→                                    <Mic className="w-5 h-5" />
   251→                                </button>
   252→                            </div>
   253→
   254→                            {/* Submit Button (Logo Animation Style: ArrowDownLeft -> Rotate 180) */}
   255→                            <button
   256→                                onClick={handleSubmit}
   257→                                disabled={!hasContent}
   258→                                className={cn(
   259→                                    "relative w-14 h-14 flex items-center justify-center rounded-full transition-all duration-500 shadow-lg group/submit",
   260→                                    hasContent
   261→                                        ? "bg-[#F75105] hover:bg-[#F78E21] hover:scale-110 shadow-[0_0_20px_rgba(247,81,5,0.3)] hover:shadow-[0_0_35px_rgba(247,81,5,0.6)] cursor-pointer"
   262→                                        : "bg-[#2F323A] cursor-not-allowed opacity-50"
   263→                                )}
   264→                                title={t?.capture?.submit || "Analyze"}
   265→                            >
   266→                                {hasContent ? (
   267→                                    <ArrowDownLeft className="w-6 h-6 text-white transition-transform duration-500 group-hover/submit:rotate-180" strokeWidth={3} />
   268→                                ) : (
   269→                                    <ArrowDownLeft className="w-6 h-6 text-[#5D5C5B]" />
   270→                                )}
   271→
   272→                                {/* Glow Effect Layer */}
   273→                                {hasContent && (
   274→                                    <div className="absolute inset-0 rounded-full bg-[#F75105] blur-md opacity-40 group-hover/submit:opacity-75 transition-opacity duration-500 -z-10"></div>
   275→                                )}
   276→                            </button>
   277→                        </div>
   278→                    </div>
   279→                )}
   280→
   281→                {/* VIEW: ANALYSIS & RESULTS */}
   282→                {viewMode === "ANALYZING" && (
   283→                    <AnalysisResults
   284→                        isActive={true}
   285→                        onReset={handleReset}
   286→                        inputData={{ text: input, files, links }}
   287→                    />
   288→                )}
   289→
   290→            </main>
   291→        </div>
   292→    );
   293→}
   294→

<system-reminder>
Whenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.
</system-reminder>

     1→"use client";
     2→
     3→import { useEffect, useState } from "react";
     4→import { cn } from "@/lib/utils";
     5→import { CheckCircle2, RotateCcw, LayoutDashboard, BrainCircuit, AlertTriangle, XCircle, ArrowRight } from "lucide-react";
     6→import { Button } from "@/components/ui/button";
     7→import { useRouter } from "next/navigation";
     8→import { toast } from "sonner";
     9→import { useLanguageStore } from "@/store/language-store";
    10→
    11→interface AnalysisResult {
    12→    viabilityScore: number;
    13→    classification: string;
    14→    summary: string;
    15→    experts: {
    16→        role: string;
    17→        status: "VALIDATED" | "WARNING" | "CRITICAL";
    18→        analysis: string;
    19→    }[];
    20→    status?: number;
    21→    error?: string;
    22→    nextSteps?: string[];
    23→}
    24→
    25→export function AnalysisResults({
    26→    isActive,
    27→    onReset,
    28→    inputData
    29→}: {
    30→    isActive: boolean;
    31→    onReset: () => void;
    32→    inputData: { text: string; files: any[]; links: string[] };
    33→}) {
    34→    const router = useRouter();
    35→    const { t, currentLang } = useLanguageStore();
    36→    const [step, setStep] = useState(0);
    37→    const [logs, setLogs] = useState<string[]>([]);
    38→    const [showResult, setShowResult] = useState(false);
    39→    const [result, setResult] = useState<AnalysisResult | null>(null);
    40→    const [isDemoMode, setIsDemoMode] = useState(false);
    41→
    42→    // Experts definition with dynamic translations
    43→    const expertsList = [
    44→        { id: "SYS_INGEST", name: (t?.analysis?.experts as any)?.SYS_INGEST || "System Ingestion", role: "Telemetry" },
    45→        { id: "AGT_MA", name: (t?.analysis?.experts as any)?.AGT_MA || "Market Analyst", role: "Sentiment" },
    46→        { id: "AGT_FIN", name: (t?.analysis?.experts as any)?.AGT_FIN || "Financial Model", role: "P&L Projection" },
    47→        { id: "AGT_TECH", name: (t?.analysis?.experts as any)?.AGT_TECH || "Tech Feasibility", role: "Stack Audit" },
    48→        { id: "AGT_LEG", name: (t?.analysis?.experts as any)?.AGT_LEG || "Legal Compliance", role: "Risk Check" },
    49→        { id: "SYS_STRUCT", name: (t?.analysis?.experts as any)?.SYS_STRUCT || "Structuration", role: "Canvas Gen" },
    50→        { id: "SYS_SCORE", name: (t?.analysis?.experts as any)?.SYS_SCORE || "Viability Scoring", role: "Algo V4" },
    51→    ];
    52→
    53→    const getDemoResult = (): AnalysisResult => {
    54→        const d = (t?.analysis as any)?.demoResult;
    55→        return {
    56→            viabilityScore: 88,
    57→            classification: "INCUBATE",
    58→            summary: d?.summary || "Strong market potential detected. The core value proposition aligns with current 'No-Code' trends, but the monetization strategy needs refinement to unlock Series A potential.",
    59→            experts: [
    60→                {
    61→                    role: d?.experts?.strategist?.role || "Product Strategist",
    62→                    status: "VALIDATED",
    63→                    analysis: d?.experts?.strategist?.analysis || "Value proposition is clear and addresses a latent market need."
    64→                },
    65→                {
    66→                    role: d?.experts?.business?.role || "Business Model",
    67→                    status: "WARNING",
    68→                    analysis: d?.experts?.business?.analysis || "CAC/LTV ratio assumes viral growth. Conservative modeling recommended."
    69→                },
    70→                {
    71→                    role: d?.experts?.tech?.role || "Tech Architect",
    72→                    status: "VALIDATED",
    73→                    analysis: d?.experts?.tech?.analysis || "Stack choice (Next.js + Supabase) is optimal for rapid MVP scaling."
    74→                },
    75→            ],
    76→            nextSteps: d?.nextSteps || ["Refine pricing model", "Launch MVP in 4 weeks", "Start community building"]
    77→        };
    78→    };
    79→
    80→    const addLog = (msg: string) => setLogs(prev => [...prev.slice(-6), `> ${msg}`]);
    81→    const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));
    82→
    83→    useEffect(() => {
    84→        if (!isActive) {
    85→            setStep(0);
    86→            setLogs([]);
    87→            setShowResult(false);
    88→            setResult(null);
    89→            setIsDemoMode(false);
    90→            return;
    91→        }
    92→
    93→        const runAnalysis = async () => {
    94→            setIsDemoMode(false);
    95→
    96→            // Step 1: Sequence Start
    97→            addLog(t?.analysis?.logs?.init || "Initialising Sequence...");
    98→            await delay(800);
    99→
   100→            // API Call Trigger
   101→            const apiCall = fetch("/api/analyze", {
   102→                method: "POST",
   103→                headers: { "Content-Type": "application/json" },
   104→                body: JSON.stringify({ ...inputData, lang: currentLang }),
   105→            }).then(async (res) => {
   106→                const data = await res.json();
   107→                if (res.status === 429 || data.error === "QUOTA_EXCEEDED") throw new Error("QUOTA_EXCEEDED");
   108→                if (!res.ok) throw new Error(data.details || "Analysis failed");
   109→                return data;
   110→            });
   111→
   112→            // Animate Experts
   113→            for (let i = 0; i < expertsList.length; i++) {
   114→                setStep(i + 1);
   115→                addLog(`[${expertsList[i].id}] Active: ${expertsList[i].name}...`);
   116→                await delay(300 + Math.random() * 300);
   117→            }
   118→
   119→            addLog(t?.analysis?.logs?.computing || "Computing Viability Matrix...");
   120→
   121→            try {
   122→                const data = await apiCall;
   123→                setResult(data);
   124→            } catch (error: any) {
   125→                console.warn("Analysis API failed:", error);
   126→                if (error.message === "QUOTA_EXCEEDED") {
   127→                    addLog(t?.analysis?.logs?.quotaWarning || "Quota Exceeded");
   128→                    setIsDemoMode(true);
   129→                    setResult(getDemoResult());
   130→                    toast.warning(t?.analysis?.logs?.demoMode || "Demo Mode", {
   131→                        description: t?.analysis?.logs?.demoDesc || "Quota reached"
   132→                    });
   133→                } else {
   134→                    addLog(t?.analysis?.logs?.error || "Critical Error");
   135→                    toast.error(t?.analysis?.logs?.analysisFailed || "Analysis Failed");
   136→                }
   137→            }
   138→
   139→            await delay(500);
   140→            setShowResult(true);
   141→        };
   142→
   143→        runAnalysis();
   144→    }, [isActive, inputData, currentLang, t]);
   145→
   146→    const handleOpenWorkspace = () => {
   147→        if (result) {
   148→            const workspaceData = {
   149→                ...inputData,
   150→                analysis: result,
   151→                timestamp: new Date().toISOString(),
   152→                isDemo: isDemoMode
   153→            };
   154→            localStorage.setItem("k3rn_active_project", JSON.stringify(workspaceData));
   155→        }
   156→        router.push("/workspace");
   157→    };
   158→
   159→    if (!isActive) return null;
   160→
   161→    return (
   162→        <div className="w-full max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-8 duration-700 ease-out">
   163→            {!showResult ? (
   164→                // LOADING STATE (Phoenix Style)
   165→                <div className="bg-[#2F323A] rounded-xl shadow-2xl p-8 border border-white/5 flex flex-col items-center gap-8 min-h-[400px] justify-center relative overflow-hidden">
   166→                    {/* Background Pulse */}
   167→                    <div className="absolute inset-0 bg-[#F75105]/5 animate-pulse" />
   168→
   169→                    <div className="flex flex-col items-center gap-4 z-10">
   170→                        <div className="relative">
   171→                            <BrainCircuit className="w-16 h-16 text-[#F75105] animate-pulse" />
   172→                            <div className="absolute inset-0 bg-[#F75105] blur-xl opacity-20 animate-pulse" />
   173→                        </div>
   174→                        <h2 className="text-xl font-sans font-medium text-white tracking-widest uppercase">
   175→                            {t?.analysis?.title || "Committee Analysis"}
   176→                        </h2>
   177→                    </div>
   178→
   179→                    {/* Progress Bar */}
   180→                    <div className="w-full max-w-md h-1 bg-[#3A3D45] rounded-full overflow-hidden">
   181→                        <div
   182→                            className="h-full bg-[#F75105] transition-all duration-300 ease-out"
   183→                            style={{ width: `${(step / expertsList.length) * 100}%` }}
   184→                        />
   185→                    </div>
   186→
   187→                    {/* Console Logs */}
   188→                    <div className="w-full max-w-md h-32 font-mono text-xs text-gray-400 space-y-1.5 p-4 rounded-lg bg-black/20 border border-white/5 overflow-hidden">
   189→                        {logs.map((log, i) => (
   190→                            <p key={i} className="animate-in slide-in-from-left-2 fade-in">
   191→                                {log}
   192→                            </p>
   193→                        ))}
   194→                        <span className="w-2 h-4 bg-[#F75105] animate-blink block mt-1" />
   195→                    </div>
   196→                </div>
   197→            ) : (
   198→                // RESULT STATE (Phoenix Style)
   199→                <div className="bg-[#2F323A] rounded-xl shadow-2xl border-0 overflow-hidden ring-1 ring-white/5 animate-in zoom-in-95 duration-500">
   200→                    <div className="grid md:grid-cols-[280px_1fr] h-full min-h-[500px]">
   201→
   202→                        {/* Sidebar: Score */}
