     1→/**
     2→ * K3RN.LABS — Détection et priorisation de l'enrichissement
     3→ * Source de vérité : Contrat Questions Guidées & Enrichissement v1.1
     4→ */
     5→
     6→import {
     7→  ANALYSIS_AXES,
     8→  CANONICAL_WEIGHTS,
     9→  ENRICHMENT_THRESHOLDS,
    10→  ENRICHMENT_LIMITS,
    11→  SCORE_RANGE,
    12→  type AnalysisAxis,
    13→} from './constants';
    14→import type { AnalysisAxes, AnalysisDecision, EnrichmentQuestion } from './types';
    15→import { calculateGlobalScore } from './scoring';
    16→
    17→// ═══════════════════════════════════════════════════════════════════
    18→// TRIGGER DETECTION (Section 3.1)
    19→// ═══════════════════════════════════════════════════════════════════
    20→
    21→export interface EnrichmentTrigger {
    22→  type: 'axis_below_threshold' | 'low_confidence_medium_score' | 'information_gap';
    23→  axis?: AnalysisAxis;
    24→  details: string;
    25→}
    26→
    27→/**
    28→ * Détecte les déclencheurs d'enrichissement canoniques.
    29→ *
    30→ * Déclencheur 1 : Axe avec score < 40 ET blocking_gap = false
    31→ * Déclencheur 2 : Score global [50, 70[ ET confidence = LOW
    32→ * Déclencheur 3 : Expert signale information_gap (non implémenté ici, dépend du LLM)
    33→ */
    34→export function detectEnrichmentTriggers(
    35→  analysis: AnalysisAxes,
    36→  globalScore: number,
    37→  confidenceLevel: 'LOW' | 'MEDIUM' | 'HIGH'
    38→): EnrichmentTrigger[] {
    39→  const triggers: EnrichmentTrigger[] = [];
    40→
    41→  // Déclencheur 1 : axe < 40 sans blocking_gap
    42→  for (const axis of ANALYSIS_AXES) {
    43→    const axisData = analysis[axis];
    44→    if (
    45→      axisData.score < ENRICHMENT_THRESHOLDS.AXIS_SCORE_MIN &&
    46→      !axisData.blocking_gap
    47→    ) {
    48→      triggers.push({
    49→        type: 'axis_below_threshold',
    50→        axis,
    51→        details: `Score ${axis} (${axisData.score}) < ${ENRICHMENT_THRESHOLDS.AXIS_SCORE_MIN}`,
    52→      });
    53→    }
    54→  }
    55→
    56→  // Déclencheur 2 : score global [50, 70[ ET confidence LOW
    57→  if (
    58→    globalScore >= ENRICHMENT_THRESHOLDS.GLOBAL_SCORE_MIN &&
    59→    globalScore < ENRICHMENT_THRESHOLDS.GLOBAL_SCORE_MAX &&
    60→    confidenceLevel === 'LOW'
    61→  ) {
    62→    triggers.push({
    63→      type: 'low_confidence_medium_score',
    64→      details: `Score global (${globalScore}) dans [50, 70[ avec confidence LOW`,
    65→    });
    66→  }
    67→
    68→  return triggers;
    69→}
    70→
    71→// ═══════════════════════════════════════════════════════════════════
    72→// AXIS PRIORITIZATION (Section 3.2)
    73→// ═══════════════════════════════════════════════════════════════════
    74→
    75→export interface PrioritizedAxis {
    76→  axis: AnalysisAxis;
    77→  score: number;
    78→  weight: number;
    79→  priority: number; // (100 - score) × weight
    80→}
    81→
    82→/**
    83→ * Priorise les axes à enrichir selon l'algorithme canonique.
    84→ *
    85→ * score_priorite = (100 - score_axe) × pondération_axe
    86→ * Sélectionne les top 2 axes.
    87→ */
    88→export function prioritizeAxes(
    89→  analysis: AnalysisAxes,
    90→  triggers: EnrichmentTrigger[]
    91→): PrioritizedAxis[] {
    92→  // Collecter les axes éligibles (ceux qui ont un trigger)
    93→  const eligibleAxes = new Set<AnalysisAxis>();
    94→  for (const trigger of triggers) {
    95→    if (trigger.axis) {
    96→      eligibleAxes.add(trigger.axis);
    97→    }
    98→  }
    99→
   100→  // Si déclencheur 2 (low confidence) sans axe spécifique,
   101→  // prioriser parmi tous les axes avec score < 70
   102→  if (triggers.some((t) => t.type === 'low_confidence_medium_score')) {
   103→    for (const axis of ANALYSIS_AXES) {
   104→      if (analysis[axis].score < 70 && !analysis[axis].blocking_gap) {
   105→        eligibleAxes.add(axis);
   106→      }
   107→    }
   108→  }
   109→
   110→  // Calculer le score de priorité pour chaque axe éligible
   111→  const prioritized: PrioritizedAxis[] = [];
   112→  for (const axis of eligibleAxes) {
   113→    const score = analysis[axis].score;
   114→    const weight = CANONICAL_WEIGHTS[axis];
   115→    const priority = (100 - score) * weight;
   116→
   117→    prioritized.push({ axis, score, weight, priority });
   118→  }
   119→
   120→  // Trier par priorité décroissante
   121→  prioritized.sort((a, b) => b.priority - a.priority);
   122→
   123→  // Limiter à max 2 axes
   124→  return prioritized.slice(0, ENRICHMENT_LIMITS.MAX_AXES);
   125→}
   126→
   127→// ═══════════════════════════════════════════════════════════════════
   128→// ENRICHMENT RESULT BUILDER
   129→// ═══════════════════════════════════════════════════════════════════
   130→
   131→/**
   132→ * Détermine si l'enrichissement est requis et quels axes cibler.
   133→ */
   134→export function computeEnrichmentDecision(
   135→  analysis: AnalysisAxes,
   136→  globalScore: number,
   137→  confidenceLevel: 'LOW' | 'MEDIUM' | 'HIGH'
   138→): {
   139→  required: boolean;
   140→  trigger_axes: AnalysisAxis[];
   141→  max_questions: number;
   142→} {
   143→  const triggers = detectEnrichmentTriggers(analysis, globalScore, confidenceLevel);
   144→
   145→  if (triggers.length === 0) {
   146→    return { required: false, trigger_axes: [], max_questions: 0 };
   147→  }
   148→
   149→  const prioritized = prioritizeAxes(analysis, triggers);
   150→  const triggerAxes = prioritized.map((p) => p.axis);
   151→
   152→  // Max questions : jusqu'à 3 par axe, max 5 au total
   153→  const maxPerAxes = triggerAxes.length * ENRICHMENT_LIMITS.MAX_QUESTIONS_PER_AXIS;
   154→  const maxQuestions = Math.min(maxPerAxes, ENRICHMENT_LIMITS.MAX_QUESTIONS_PER_SEQUENCE);
   155→
   156→  return {
   157→    required: true,
   158→    trigger_axes: triggerAxes,
   159→    max_questions: maxQuestions,
   160→  };
   161→}
   162→
   163→// ═══════════════════════════════════════════════════════════════════
   164→// SCORE RECALCULATION AFTER ENRICHMENT (Section 8)
   165→// ═══════════════════════════════════════════════════════════════════
   166→
   167→export interface ScoreAdjustment {
   168→  axis: AnalysisAxis;
   169→  question_id: string;
   170→  adjustment: number;
   171→}
   172→
   173→/**
   174→ * Applique les ajustements de score après enrichissement.
   175→ * Recalcule le score global et réévalue la décision.
   176→ *
   177→ * Règles :
   178→ * - score_enrichi = score_initial + Σ(ajustements)
   179→ * - Bornage [0, 100]
   180→ * - Recalcul complet du score global
   181→ * - Mise à jour confidence : LOW → MEDIUM si 2+ axes enrichis
   182→ */
   183→export function applyEnrichmentAdjustments(
   184→  currentAnalysis: AnalysisAxes,
   185→  adjustments: ScoreAdjustment[]
   186→): {
   187→  updatedAnalysis: AnalysisAxes;
   188→  newGlobalScore: number;
   189→  enrichedAxes: Set<AnalysisAxis>;
   190→} {
   191→  const updatedAnalysis: AnalysisAxes = JSON.parse(JSON.stringify(currentAnalysis));
   192→  const enrichedAxes = new Set<AnalysisAxis>();
   193→
   194→  // Grouper les ajustements par axe et appliquer
   195→  for (const adj of adjustments) {
   196→    const currentScore = updatedAnalysis[adj.axis].score;
   197→    updatedAnalysis[adj.axis].score = Math.max(
   198→      SCORE_RANGE.MIN,
   199→      Math.min(SCORE_RANGE.MAX, currentScore + adj.adjustment)
   200→    );
   201→    enrichedAxes.add(adj.axis);
   202→  }
   203→
   204→  const newGlobalScore = calculateGlobalScore(updatedAnalysis);
   205→
   206→  return { updatedAnalysis, newGlobalScore, enrichedAxes };
   207→}
   208→
   209→/**
   210→ * Met à jour le niveau de confiance après enrichissement.
   211→ * LOW → MEDIUM si 2+ axes ont été enrichis.
   212→ * MEDIUM → HIGH si tous les axes enrichis ont score >= 60.
   213→ */
   214→export function updateConfidenceLevel(
   215→  currentLevel: 'LOW' | 'MEDIUM' | 'HIGH',
   216→  enrichedAxes: Set<AnalysisAxis>,
   217→  updatedAnalysis: AnalysisAxes
   218→): 'LOW' | 'MEDIUM' | 'HIGH' {
   219→  if (currentLevel === 'HIGH') return 'HIGH';
   220→
   221→  if (currentLevel === 'LOW' && enrichedAxes.size >= 2) {
   222→    return 'MEDIUM';
   223→  }
   224→
   225→  if (currentLevel === 'MEDIUM') {
   226→    const allAbove60 = Array.from(enrichedAxes).every(
   227→      (axis) => updatedAnalysis[axis].score >= 60
   228→    );
   229→    if (allAbove60 && enrichedAxes.size >= 2) {
   230→      return 'HIGH';
   231→    }
   232→  }
   233→
   234→  return currentLevel;
   235→}
