     1→"use client";
     2→
     3→import { useEffect, useState, useCallback, useRef } from "react";
     4→
     5→if (typeof window !== "undefined") {
     6→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
     7→    (window as any).SpeechRecognition =
     8→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
     9→        (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    10→}
    11→
    12→
    13→
    14→export function useSpeechRecognition({
    15→    onFinal,
    16→    onInterim,
    17→    onError,
    18→}: {
    19→    onFinal?: (text: string) => void;
    20→    onInterim?: (text: string) => void;
    21→    onError?: (error: string) => void;
    22→} = {}) {
    23→    const [isRecording, setIsRecording] = useState(false);
    24→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    25→    const recognitionRef = useRef<any>(null);
    26→
    27→    const startRecording = useCallback(() => {
    28→        if (!("SpeechRecognition" in window) && !("webkitSpeechRecognition" in window)) {
    29→            onError?.("La reconnaissance vocale n'est pas supportée par ce navigateur.");
    30→            return;
    31→        }
    32→
    33→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
    34→        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    35→        const recognition = new SpeechRecognition();
    36→
    37→        recognition.continuous = true;
    38→        recognition.interimResults = true;
    39→        recognition.lang = document.documentElement.lang || "fr-FR";
    40→
    41→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
    42→        recognition.onresult = (event: any) => {
    43→            let interimTranscript = "";
    44→
    45→            for (let i = event.resultIndex; i < event.results.length; ++i) {
    46→                if (event.results[i].isFinal) {
    47→                    onFinal?.(event.results[i][0].transcript);
    48→                } else {
    49→                    interimTranscript += event.results[i][0].transcript;
    50→                }
    51→            }
    52→
    53→            if (interimTranscript) {
    54→                onInterim?.(interimTranscript);
    55→            }
    56→        };
    57→
    58→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
    59→        recognition.onerror = (event: any) => {
    60→            console.error("Speech recognition error", event.error);
    61→            if (event.error === "no-speech") {
    62→                return; // Ignore no-speech errors usually
    63→            }
    64→            onError?.(event.error);
    65→        };
    66→
    67→        recognition.onend = () => {
    68→            setIsRecording(false);
    69→        };
    70→
    71→        try {
    72→            recognition.start();
    73→            recognitionRef.current = recognition;
    74→            setIsRecording(true);
    75→        } catch (e) {
    76→            console.error("Failed to start recognition", e);
    77→            setIsRecording(false);
    78→        }
    79→    }, [onFinal, onInterim, onError]);
    80→
    81→    const stopRecording = useCallback(() => {
    82→        if (recognitionRef.current) {
    83→            recognitionRef.current.stop();
    84→            setIsRecording(false);
    85→        }
    86→    }, []);
    87→
    88→    const toggleRecording = useCallback(() => {
    89→        if (isRecording) {
    90→            stopRecording();
    91→        } else {
    92→            startRecording();
    93→        }
    94→    }, [isRecording, startRecording, stopRecording]);
    95→
    96→    useEffect(() => {
    97→        return () => {
    98→            if (recognitionRef.current) {
    99→                recognitionRef.current.stop();
   100→            }
   101→        };
   102→    }, []);
   103→
   104→    return {
   105→        isRecording,
   106→        startRecording,
   107→        stopRecording,
   108→        toggleRecording,
   109→    };
   110→}
