   178→    lab: z.enum(['DISCOVERY', 'MARKET', 'STRATEGY', 'TECH', 'BUSINESS', 'NONE']),
   179→    reason: z.string().min(10).max(200),
   180→  }),
   181→});
   182→
   183→// ═══════════════════════════════════════════════════════════════════
   184→// ENRICHMENT VALIDATORS (Widget Schema v1.0)
   185→// ═══════════════════════════════════════════════════════════════════
   186→
   187→const questionOptionSchema = z.object({
   188→  id: z.string().min(1),
   189→  label: z.string().min(1),
   190→  value: z.string().min(1),
   191→  score_adjustment: z.number().min(-25).max(25),
   192→});
   193→
   194→export const enrichmentQuestionSchema = z.object({
   195→  question_id: z.string().min(1),
   196→  axis: axisEnum,
   197→  type: z.enum(['single_select', 'multi_select', 'range', 'ranking']),
   198→  prompt: z.string().min(10).max(200),
   199→  options: z.array(questionOptionSchema).min(2).max(5),
   200→  allow_skip: z.boolean(),
   201→  timeout_seconds: z.number().int().min(1),
   202→  expected_impact: z.object({
   203→    axis: axisEnum,
   204→    min_adjustment: z.number(),
   205→    max_adjustment: z.number(),
   206→  }),
   207→});
   208→
   209→export const enrichmentResponseSchema = z.object({
   210→  question_id: z.string().min(1),
