   238→
   239→export function validateAnalysisOutput(data: unknown): ValidationResult<z.infer<typeof analysisOutputSchema>> {
   240→  const result = analysisOutputSchema.safeParse(data);
   241→  if (result.success) {
   242→    return { valid: true, data: result.data };
   243→  }
   244→  return {
   245→    valid: false,
   246→    errors: result.error.issues.map(
   247→      (issue) => `${issue.path.join('.')} ${issue.message}`
   248→    ),
   249→  };
   250→}
   251→
   252→export function validateLlmRawOutput(data: unknown): ValidationResult<z.infer<typeof llmRawOutputSchema>> {
   253→  const result = llmRawOutputSchema.safeParse(data);
   254→  if (result.success) {
   255→    return { valid: true, data: result.data };
   256→  }
   257→  return {
   258→    valid: false,
   259→    errors: result.error.issues.map(
